import React from "react";
import { useParams } from "react-router-dom";
import "../styles/NewsDetail.css";

const newsDetails = [
  {
    id: 1,
    title: "Post 1 Title",
    description: "This is the full description for the first news post. It contains all the details about the post.",
    image: "/images/news1.jpg",
  },
  {
    id: 2,
    title: "Post 2 Title",
    description: "This is the full description for the second news post. It contains all the details about the post.",
    image: "/images/news2.jpg",
  },
  {
    id: 3,
    title: "Post 3 Title",
    description: "This is the full description for the third news post. It contains all the details about the post.",
    image: "/images/news3.jpg",
  },
];

const NewsDetail = () => {
  const { id } = useParams();
  const post = newsDetails.find((post) => post.id === parseInt(id));

  return (
    <div className="news-detail">
      <h2>{post?.title}</h2>
      <img src={post?.image} alt={post?.title} className="news-detail-image" />
      <p>{post?.description}</p>
    </div>
  );
};

export default NewsDetail;
